function i(a){const n=[...a];for(let t=n.length-1;t>0;t--){const r=Math.floor(Math.random()*(t+1));[n[t],n[r]]=[n[r],n[t]]}return n}function l(a,n,t){let r=[...a],e=[...n];const o=[];for(let d=0;d<t;d++){if(r.length===0){if(e.length===0){console.warn("[Ascendant] draw: deck and discard both empty");break}r=i(e),e=[]}o.push(r.pop())}return{drawn:o,deck:r,discard:e}}function s(a,n,t,r){const e=[...a,...n,...t,r].filter(Boolean);return i(e)}export{s as b,l as d,i as s};
